"use client";

import axios, { AxiosInstance, AxiosRequestConfig } from "axios";
import { WORKFLOW_API_BASE_URL, WORKFLOW_API_KEY } from "@/lib/config";

export interface WorkflowJob {
  id: string;
  name: string;
  status: string;
  state_index: number;
  assignee_email: string | null;
  system_department: string | null;
  external_job_id: string | null;
  is_revision: boolean;
  metadata: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface JobListResponse {
  jobs: WorkflowJob[];
  count: number;
  total?: number;
}

export interface JobQueryParams {
  assignee_email?: string;
  system_department?: string;
  status?: string;
  limit?: number;
  offset?: number;
}

// Lazy initialization for the Axios instance
let workflowApiClient: AxiosInstance | null = null;

/**
 * Get or create the workflow API Axios instance
 * API key is injected at request time via interceptor (not baked at build time)
 */
function getWorkflowApiClient(): AxiosInstance {
  if (workflowApiClient) {
    return workflowApiClient;
  }

  if (!WORKFLOW_API_BASE_URL) {
    throw new Error("Workflow API base URL not configured");
  }

  workflowApiClient = axios.create({
    baseURL: WORKFLOW_API_BASE_URL,
    headers: {
      "Content-Type": "application/json",
    },
  });

  // Request interceptor to inject API key at request time
  workflowApiClient.interceptors.request.use(
    (config) => {
      if (WORKFLOW_API_KEY) {
        config.headers["x-api-key"] = WORKFLOW_API_KEY;
      }
      return config;
    },
    (error) => {
      return Promise.reject(error);
    },
  );

  // Response interceptor for error handling
  workflowApiClient.interceptors.response.use(
    (response) => response,
    (error) => {
      if (error.response?.status === 401) {
        console.error("Workflow API authentication failed");
      }
      return Promise.reject(error);
    },
  );

  return workflowApiClient;
}

/**
 * Fetch jobs from the workflow engine
 * Direct client-side call to workflow API (bypasses Next.js proxy for specific use cases)
 */
export async function fetchWorkflowJobs(params: JobQueryParams = {}): Promise<JobListResponse> {
  const client = getWorkflowApiClient();

  const queryParams = new URLSearchParams();
  if (params.assignee_email) {
    queryParams.append("assignee_email", params.assignee_email);
  }
  if (params.system_department) {
    queryParams.append("system_department", params.system_department);
  }
  if (params.status) {
    queryParams.append("status", params.status);
  }
  queryParams.append("limit", String(params.limit || 100));
  queryParams.append("offset", String(params.offset || 0));

  const queryString = queryParams.toString();
  const url = `/api/jobs${queryString ? `?${queryString}` : ""}`;

  const response = await client.get<
    WorkflowJob[] | { jobs: WorkflowJob[] } | { data: WorkflowJob[] }
  >(url);

  // Normalize response format
  let jobs: WorkflowJob[] = [];
  const data = response.data;

  if (Array.isArray(data)) {
    jobs = data;
  } else if ("jobs" in data) {
    jobs = data.jobs;
  } else if ("data" in data) {
    jobs = data.data;
  }

  return {
    jobs,
    count: jobs.length,
    total: response.headers["x-total-count"]
      ? parseInt(response.headers["x-total-count"], 10)
      : undefined,
  };
}

/**
 * Fetch a single job by ID
 */
export async function fetchWorkflowJob(jobId: string): Promise<WorkflowJob> {
  const client = getWorkflowApiClient();
  const response = await client.get<WorkflowJob>(`/api/jobs/${jobId}`);
  return response.data;
}

/**
 * Update job status
 */
export async function updateWorkflowJobStatus(
  jobId: string,
  status: string,
  metadata?: Record<string, unknown>,
): Promise<WorkflowJob> {
  const client = getWorkflowApiClient();
  const response = await client.patch<WorkflowJob>(`/api/jobs/${jobId}`, {
    status,
    ...(metadata && { metadata }),
  });
  return response.data;
}

/**
 * Check if workflow API is configured and accessible
 */
export function isWorkflowApiConfigured(): boolean {
  return Boolean(WORKFLOW_API_BASE_URL && WORKFLOW_API_KEY);
}

/**
 * Get workflow API health/status
 * Useful for checking connectivity before operations
 */
export async function checkWorkflowApiHealth(): Promise<boolean> {
  if (!isWorkflowApiConfigured()) {
    return false;
  }

  try {
    const client = getWorkflowApiClient();
    await client.get("/api/health", { timeout: 5000 });
    return true;
  } catch {
    return false;
  }
}

export { getWorkflowApiClient };

